/// Look up the spec-driven display label for an `activity_type` string.
/// Returns `None` for non-canonical values; callers should fall back to a
/// title-case formatter (see `openbox_sdk::approvals::format::format_label`).
pub fn canonical_activity_label(activity_type: &str) -> Option<&'static str> {
    CANONICAL_ACTIVITY_LABELS
        .binary_search_by(|(k, _)| (*k).cmp(activity_type))
        .ok()
        .map(|i| CANONICAL_ACTIVITY_LABELS[i].1)
}

